const body = $input.first().json.body ?? $input.first().json;
const product = (body.product_name ?? '').trim() || null;
const goal = (body.goal ?? 'user engagement and viral content').trim();

const productContext = product
  ? `The product is: "${product}". Tailor all queries, hooks, and ideas around it. Use "${product}" wherever a product name fits naturally.`
  : 'No specific product provided. Generate niche-level beauty content. Where a product name would fit, use the placeholder "{product}" so it stays interchangeable.';

const userPrompt = `Generate a market research report for the beauty niche.

Goal: ${goal}
${productContext}

Return a JSON object with exactly this schema:
{
  "product": "<product name or null>",
  "queries": ["<5 search queries>"],
  "urls": ["<3 URLs to scrape for insights>"],
  "trends": "<paragraph describing current beauty trends>",
  "content_patterns": "<paragraph describing what content formats drive high engagement>",
  "ideas": [
    {
      "title": "<content idea title>",
      "format": "<platform and format e.g. TikTok 30s video>",
      "hook": "<opening line or visual hook>",
      "why_it_works": "<engagement reasoning>"
    }
  ]
}

Rules:
- queries: exactly 5 items
- urls: exactly 3 items
- ideas: exactly 6 items
- Return ONLY the JSON object, nothing else`;

const apiBody = JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 2048,
  system: 'You are a Market Research Analyst Agent specialized in the beauty niche. Your focus is maximizing user engagement and creating viral content. Always return ONLY valid JSON matching the required schema — no extra text, no markdown fences.',
  messages: [{ role: 'user', content: userPrompt }]
});

return [{ json: { product, goal, apiBody } }];

const raw = $input.first().json.content?.[0]?.text ?? '';
let cleaned = raw.trim();
if (cleaned.startsWith('```')) {
  cleaned = cleaned.split('```')[1] ?? '';
  if (cleaned.startsWith('json')) cleaned = cleaned.slice(4);
  cleaned = cleaned.trim();
}
let result;
try { result = JSON.parse(cleaned); }
catch (e) { return [{ json: { error: 'Failed to parse research response', raw } }]; }
return [{ json: result }];

const research = $input.first().json;
const product = research.product || null;
const productLine = product
  ? `Product: ${product}`
  : 'No specific product — use "{product}" placeholder where needed.';

const ideasText = (research.ideas || []).map((idea, i) =>
  `Idea ${i+1}: ${idea.title}
Format: ${idea.format}
Hook: ${idea.hook}`
).join('

');

const userPrompt = `You are a viral beauty content creator. Using the research below, generate ready-to-post content.

${productLine}
Trends: ${research.trends}
What performs well: ${research.content_patterns}

Content ideas to execute:
${ideasText}

For each idea, create the actual content. Return ONLY a JSON object:
{
  "product": "<product name or null>",
  "content_pieces": [
    {
      "title": "<idea title>",
      "platform": "<TikTok / Instagram Reels / YouTube Shorts>",
      "caption": "<full ready-to-post caption with emojis>",
      "script": "<spoken video script, 30-60 seconds, natural tone>",
      "visual_prompt": "<short cinematic description of visuals for AI video generation>",
      "hashtags": ["<10 relevant hashtags>"],
      "cta": "<call to action to maximize engagement>"
    }
  ]
}

Rules:
- content_pieces: exactly 6 items
- scripts must be natural and conversational, not salesy
- visual_prompt should be vivid and visual (used for AI video generation)
- Return ONLY the JSON object, nothing else`;

const apiBody = JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 4000,
  system: 'You are an expert viral beauty content creator. Always return ONLY valid JSON — no extra text, no markdown fences.',
  messages: [{ role: 'user', content: userPrompt }]
});

return [{ json: { research, apiBody } }];

const research = $('Build Content Prompt').first().json.research;
const raw = $input.first().json.content?.[0]?.text ?? '';
let cleaned = raw.trim();
if (cleaned.startsWith('```')) {
  cleaned = cleaned.split('```')[1] ?? '';
  if (cleaned.startsWith('json')) cleaned = cleaned.slice(4);
  cleaned = cleaned.trim();
}
let content;
try { content = JSON.parse(cleaned); }
catch (e) { return [{ json: { error: 'Failed to parse content response', raw } }]; }
const pieces = content.content_pieces || [];
return pieces.map(piece => ({ json: { ...piece, research_trends: research.trends } }));

const item = $input.item.json;
const script = (item.script || '').slice(0, 1500);
const body = JSON.stringify({
  video_inputs: [{
    character: {
      type: 'avatar',
      avatar_id: 'Anna_public_3_20240108',
      avatar_style: 'normal'
    },
    voice: {
      type: 'text',
      input_text: script,
      voice_id: '1bd001e7e50f421d891986aad5158bc8',
      speed: 1.0
    },
    background: {
      type: 'color',
      value: '#FAFAFA'
    }
  }],
  dimension: { width: 1080, height: 1920 },
  test: false
});
return [{ json: { ...item, heygenBody: body } }];

const original = $('Build HeyGen Body').item.json;
const response = $input.item.json;
return [{ json: {
  ...original,
  heygen_video_id: response.data?.video_id || null,
  heygen_status: response.data?.video_id ? 'processing' : 'failed'
}}];

const item = $input.item.json;
const visualPrompt = (item.visual_prompt || item.hook || '').slice(0, 500);
const body = JSON.stringify({
  promptText: `${visualPrompt} Beauty content, vertical video, vibrant colors, professional lighting`,
  model: 'gen3a_turbo',
  duration: 10,
  ratio: '768:1280'
});
return [{ json: { ...item, runwayBody: body } }];

const original = $('Build Runway Body').item.json;
const response = $input.item.json;
return [{ json: {
  ...original,
  runway_task_id: response.id || null,
  runway_status: response.id ? 'processing' : 'failed'
}}];

const items = $input.all();
const seen = new Set();
const pieces = [];
for (const item of items) {
  const key = item.json.title;
  if (!seen.has(key)) {
    seen.add(key);
    pieces.push({
      index: pieces.length + 1,
      title: item.json.title,
      platform: item.json.platform,
      caption: item.json.caption,
      script: item.json.script,
      hashtags: item.json.hashtags,
      cta: item.json.cta,
      heygen_video_id: item.json.heygen_video_id || null,
      runway_task_id: item.json.runway_task_id || null
    });
  }
}
return [{ json: {
  total: pieces.length,
  message: 'Videos are being generated. Check HeyGen and Runway dashboards in 3-5 minutes to download your videos.',
  heygen_check_url: 'https://app.heygen.com/videos',
  runway_check_url: 'https://app.runwayml.com',
  content_pieces: pieces
}}];
